import{c as a,Q as s,j as r,m as e}from"./chunks/framework.D9IbVcwA.js";const c=JSON.parse('{"title":"026-fs-ramdisk-1 · Ramdisk 文件系统","description":"","frontmatter":{"title":"026-fs-ramdisk-1 · Ramdisk 文件系统"},"headers":[],"relativePath":"hands-on/026-fs-ramdisk-1.md","filePath":"hands-on/026-fs-ramdisk-1.md","lastUpdated":1779686691000}'),i={name:"hands-on/026-fs-ramdisk-1.md"};function o(n,t,p,u,d,l){return s(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="_026-fs-ramdisk-1-ustar-格式与八进制解析" tabindex="-1">026-fs-ramdisk-1: USTAR 格式与八进制解析 <a class="header-anchor" href="#_026-fs-ramdisk-1-ustar-格式与八进制解析" aria-label="Permalink to &quot;026-fs-ramdisk-1: USTAR 格式与八进制解析&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>到这里，我们的内核已经有了串口输出、内存管理、进程调度、用户态切换、系统调用和 AHCI 磁盘驱动。但仔细想想——我们还从来没有从&quot;文件&quot;这个层面碰过磁盘上的数据。</p><p>AHCI 驱动能读写扇区，但扇区是一堆原始字节，不是文件。我们需要一个文件系统，而文件系统的起点，是先把一些文件弄到内核能碰到的地方。这就是 initrd（initial ramdisk）的用武之地。</p><p>我们现在的方案是：把一个 ustar 格式的 tar 归档直接编译进内核镜像里，内核启动时解析这个归档，列出里面的文件。这个 tag 做的就是这件事——而本篇我们聚焦在最底层：ustar 格式的定义和八进制 ASCII 解析。</p><p>完成本篇后，你会拥有一个完整定义的 ustar 头部结构和可靠的八进制转换函数，为下一篇的构建系统集成和最终的 ramdisk 驱动打下基础。前置知识：上一个 tag（025）的 AHCI 驱动不需要，本篇是纯软件层。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="什么是-ustar-格式" tabindex="-1">什么是 ustar 格式？ <a class="header-anchor" href="#什么是-ustar-格式" aria-label="Permalink to &quot;什么是 ustar 格式？&quot;">​</a></h3><p>ustar 是 POSIX.1-1988 定义的&quot;Unix Standard TAR&quot;归档格式。它的设计哲学简单到令人感动：把所有文件一个接 接拼在一起，每个文件前面加一个 512 字节的头部描述这个文件的元信息（名字、大小、类型等），文件内容也按 512 字节对齐填充。整个归档用两个全零的 512 字节块标记结束。</p><p>你完全可以把 ustar 想象成一本书：每&quot;页&quot;是 512 字节，每个文件的&quot;标题页&quot;是头部，后面跟着若干页的&quot;正文&quot;。 翻到一页全零的标题页，就说明书读完了。这个类比其实非常精确——tar 的全称是 &quot;Tape ARchive&quot;，最初就是为 磁带设计的，磁带本身就是线性顺序读取的介质，所以 tar 的线性结构并非偶然，而是和底层存储介质的高度适配。</p><p>为什么选 ustar 而不是别的格式？因为它的解析逻辑极其简单——没有压缩、没有校验和验证（可以跳过）、没有 复杂的索引结构。对于教学 OS 来说，这就是最合适的 initrd 格式。OSDev Wiki 也推荐 tar 作为入门 initrd 格式，因为它只需要一个简单的线性扫描就能列出所有文件。与之相比，cpio 格式虽然也被 Linux 的 initramfs 使用，但它的头部格式更复杂（有多种变体），gzip/bzip2 压缩则需要先解压才能解析，增加了不必要的复杂度。</p><h3 id="ustar-格式的历史背景" tabindex="-1">ustar 格式的历史背景 <a class="header-anchor" href="#ustar-格式的历史背景" aria-label="Permalink to &quot;ustar 格式的历史背景&quot;">​</a></h3><p>tar 格式诞生于 1970 年代末的 Unix V7，最初的目的就是在磁带之间传输文件。磁带是顺序访问介质——你不能 随机跳转到某个位置，只能从头到尾线性读取。这解释了为什么 tar 的结构是线性的：每个文件按顺序排列，头部 和数据交替出现。你不可能像 FAT 或 ext2 那样维护一个文件分配表，因为在磁带上&quot;跳转&quot;到文件分配表的位置 是非常慢的操作。</p><p>随着硬盘的普及，tar 的用途从&quot;磁带归档&quot;扩展为通用的文件打包格式。虽然后来出现了更多高级格式（zip 的 随机访问、7z 的高压缩率），但 tar 的简单性使它在 OS 开发领域保持着特殊的地位——当你需要在内核里实现 一个最小化的文件读取时，tar 几乎是唯一一个能在几百行代码内完成解析的格式。</p><h3 id="八进制-ascii-编码——来自磁带时代的遗产" tabindex="-1">八进制 ASCII 编码——来自磁带时代的遗产 <a class="header-anchor" href="#八进制-ascii-编码——来自磁带时代的遗产" aria-label="Permalink to &quot;八进制 ASCII 编码——来自磁带时代的遗产&quot;">​</a></h3><p>ustar 头部里有一个非常&quot;复古&quot;的设计决策：所有数字字段都用八进制的 ASCII 字符串表示，而不是二进制整数。 比如一个 100 字节的文件，它的 size 字段存的是字符串 &quot;00000000144&quot;（144 的八进制等于 100 的十进制）， 每个字符都是 &#39;0&#39; 到 &#39;7&#39; 的 ASCII 码。</p><p>这个设计来自 1970 年代的磁带时代——用 ASCII 文本存储数字可以跨平台兼容，因为不同机器的二进制整数字节序 不同（大端序 vs 小端序），整数字长也可能不同（16 位 vs 32 位），但 ASCII 字符在所有系统上都是一样的。 一个 &#39;5&#39; 的 ASCII 码 0x35，无论在 PDP-11、VAX 还是现代 x86 上都是同一个值。</p><p>字符串以 null 字符或空格字符终止——有些 tar 实现用 null，有些用空格，有些两者混合使用，我们的解析器 必须同时处理这两种情况。这种编码方式虽然浪费空间（12 字节只能表示到约 8GB），但在那个年代 8GB 是不可 想象的数字，所以完全够用。</p><p>我们需要一个函数把这个八进制 ASCII 字符串转回 64 位无符号整数。思路很直接：从左到右逐字符读取，遇到 null 或空格就停，每个数字位的值等于字符值减去 &#39;0&#39; 的 ASCII 码，然后 result 等于 result 乘以 8 加上 当前数字值。用位运算的话就是每次左移 3 位再加上数字值——位移的语义更清晰，因为八进制的基数 8 恰好是 2 的 3 次方。</p><h3 id="ustar-头部的字段布局" tabindex="-1">ustar 头部的字段布局 <a class="header-anchor" href="#ustar-头部的字段布局" aria-label="Permalink to &quot;ustar 头部的字段布局&quot;">​</a></h3><p>一个 ustar 头部固定 512 字节，我们来详细了解每个字段的含义和位置。</p><p>前 100 字节（偏移 0-99）是文件路径，以 null 字符终止，包含完整的相对路径，比如 &quot;etc/passwd&quot; 或 &quot;hello.txt&quot;。偏移 100-107 是 mode 字段，8 字节的八进制 ASCII 表示文件权限（比如 &quot;0000644 &quot; 表示 用户可读写、其他人只读）。偏移 108-115 和 116-123 分别是 uid 和 gid，各 8 字节的八进制用户/组 ID。</p><p>偏移 124-135 是 size 字段，12 字节的八进制 ASCII 表示文件大小——这是我们最关心的字段之一。偏移 136-147 是修改时间（mtime），同样 12 字节八进制。偏移 148-155 是校验和，8 字节——虽然可以用来验证 头部完整性，但我们的实现选择跳过校验和验证以简化逻辑。</p><p>偏移 156 是 typeflag，只有 1 个字节，决定了这条记录的类型：&#39;0&#39; 是普通文件，&#39;5&#39; 是目录，&#39;7&#39; 是连续 文件（和普通文件等价），&#39;1&#39; 到 &#39;6&#39; 分别是硬链接、软链接、字符设备、块设备和 FIFO。偏移 157-256 是 链接目标名称，100 字节，仅当 typeflag 为链接类型时有效。</p><p>偏移 257 开始是 ustar 扩展字段——magic 字段（偏移 257-262，6 字节）必须是 &quot;ustar&quot; 加一个 null， 如果不是，说明这不是一个合法的 ustar 头部。这是我们在 mount 遍历中验证头部合法性的关键检查。后面还有 版本号（263-264，值为 &quot;00&quot;）、用户名和组名（各 32 字节）、设备主次号（各 8 字节）和路径前缀（155 字节，用于超过 99 字节的长文件名）。最后是 12 字节的填充把头部凑满 512 字节。</p><h3 id="数据块的对齐规则" tabindex="-1">数据块的对齐规则 <a class="header-anchor" href="#数据块的对齐规则" aria-label="Permalink to &quot;数据块的对齐规则&quot;">​</a></h3><p>除了头部之外，ustar 还有一个重要的对齐规则需要理解。文件的原始数据紧跟在头部后面，但必须按 512 字节 对齐。也就是说，如果文件大小是 100 字节，它在归档中实际占用 512 字节（一个完整的数据块，剩余部分用零 填充）；如果文件大小是 600 字节，实际占用 1024 字节（两个数据块）；如果文件大小恰好是 512 字节，占用 512 字节（一个数据块，恰好填满）。</p><p>当文件大小为 0 时不占任何数据块——下一个头部直接紧跟在当前头部后面。目录条目的 size 通常也是 0，所以 目录头部后面也是直接接下一个条目。这个对齐规则直接影响 mount 时如何从一个条目跳到下一个条目：跳转量 等于 512（头部大小）加上向上取整（文件大小除以 512）再乘以 512（数据块）。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-定义-ustar-常量" tabindex="-1">Step 1: 定义 ustar 常量 <a class="header-anchor" href="#step-1-定义-ustar-常量" aria-label="Permalink to &quot;Step 1: 定义 ustar 常量&quot;">​</a></h3><p><strong>目标</strong>: 创建配置头文件 <code>ramdisk_config.hpp</code>，定义 ustar 相关的常量和类型标志。</p><p><strong>设计思路</strong>: 我们把 ustar 格式的定义和实际的 ramdisk 驱动逻辑分成两个独立的头文件。配置层只负责描述 &quot;ustar 是什么样的&quot;，不涉及任何内核特定功能（不包含 kprintf 头文件、不依赖链接器符号）。这样 host 端 的单元测试也能包含这个头文件来测试格式定义，不需要链接整个内核。所有定义放在 cinux::fs 命名空间下， 避免全局命名空间污染。</p><p><strong>实现约束</strong>: 定义一个 32 位无符号常量表示块大小（512 字节），这个常量会在数据块数计算和 mount 偏移 跳转中使用。定义一个命名空间包含 8 个类型标志字符常量：普通文件、目录、硬链接、软链接、字符设备、 块设备、FIFO 和连续文件。定义一个字符串常量 &quot;ustar&quot; 作为 magic 验证值。</p><p>类型标志用 constexpr char 而不是枚举，因为 typeflag 在头部中就是单个 char 字段，直接用 char 比较 更自然，避免了枚举和 char 之间的反复类型转换带来的代码冗余。</p><p><strong>踩坑预警</strong>: 常量必须用 static constexpr 而不是宏定义，这样才能在编译期断言和模板中使用，而且有类型 安全。magic 字符串用 static constexpr char 数组定义，包含 null 终止符共 6 个字符。</p><p><strong>验证</strong>: 编写测试确认块大小常量值为 512，类型标志字符与 POSIX 定义一致（&#39;0&#39; 到 &#39;7&#39;），magic 字符串 前 5 个字符确实是 &quot;ustar&quot; 且第 6 个字符是 null 终止符。</p><h3 id="step-2-定义-ustarheader-结构体" tabindex="-1">Step 2: 定义 UstarHeader 结构体 <a class="header-anchor" href="#step-2-定义-ustarheader-结构体" aria-label="Permalink to &quot;Step 2: 定义 UstarHeader 结构体&quot;">​</a></h3><p><strong>目标</strong>: 定义与 ustar 头部完全对应的内存布局结构体。</p><p><strong>设计思路</strong>: ustar 头部是 512 字节的固定格式，每个字段在固定偏移量上。我们用一个 packed struct 来 精确映射这个布局，这样可以直接把指向归档数据的指针重解释为这个结构体指针来访问字段。这在 OS 开发中是 非常常见的模式——当你需要直接把硬件寄存器、协议头部或磁盘数据映射为 C/C++ 结构体时，packed struct 是 标准做法。</p><p><strong>实现约束</strong>: 结构体必须使用 GNU 特定的 packed 属性防止编译器插入填充字节，所有字段都是 char 数组 （对应 ASCII 字符串）。字段按 POSIX 规范的偏移量严格排列：name 数组 100 字节在偏移 0，mode 数组 8 字节在偏移 100，size 数组 12 字节在偏移 124，typeflag 单字节在偏移 156，magic 数组 6 字节在偏移 257，prefix 数组 155 字节在偏移 345，最后 padding 数组 12 字节凑满 512 字节。</p><p>必须在结构体定义后立即加编译期断言验证大小为 512——如果编译失败，说明字段定义有误。</p><p><strong>踩坑预警</strong>: 如果不用 packed 属性，编译器可能会在 typeflag（只有 1 字节）后面插入填充字节让后续字段 对齐到合理边界，导致结构体大小超过 512 字节。这种情况下用指针重解释映射的数据会全部错位，而且这个 bug 非常隐蔽——你可能只发现文件名变成了乱码，却不知道根因在结构体布局上。编译期断言是你唯一的安全网。</p><p>另外，字段顺序必须和 POSIX 规范一致——如果你把两个字段写反了，编译不会报错（它们类型相同），但运行时 所有偏移量都会错位。</p><p><strong>验证</strong>: 编写测试检查每个关键字段的偏移量：name 在偏移 0，mode 在偏移 100，size 在偏移 124，typeflag 在偏移 156，magic 在偏移 257，prefix 在偏移 345。具体做法是创建一个头部实例，获取其基地址的 uint8_t 指针，然后分别计算每个字段成员的地址与基地址的差值。</p><h3 id="step-3-实现-octal-to-uint-转换函数" tabindex="-1">Step 3: 实现 octal_to_uint 转换函数 <a class="header-anchor" href="#step-3-实现-octal-to-uint-转换函数" aria-label="Permalink to &quot;Step 3: 实现 octal_to_uint 转换函数&quot;">​</a></h3><p><strong>目标</strong>: 实现将八进制 ASCII 字符串转换为 64 位无符号整数的函数。</p><p><strong>设计思路</strong>: ustar 的 size、mode、uid 等数字字段都是八进制 ASCII。我们需要一个通用的转换函数，接受 字符指针和最大长度，返回解析后的整数。函数要能正确处理 null 终止和空格终止两种情况。</p><p>作为自由函数而非头部结构体的成员方法，因为它不操作任何实例，而且需要被 host 测试和内核代码分别独立 调用。声明在 config 头文件中，实现在 ramdisk.cpp 中。</p><p><strong>实现约束</strong>: 函数签名接受一个 const char 指针和一个 size_t 长度参数，返回 uint64_t。循环遍历字符， 遇到 null 或空格就跳出。每个有效字符的数字值等于字符的 ASCII 码减去 &#39;0&#39; 的 ASCII 码，累积公式用位移 实现：每次左移 3 位再加上当前数字值。</p><p><strong>踩坑预警</strong>: 有几个容易忽略的边界情况需要注意。空字符串（长度为 0）应该返回 0。全是空格的字段也应该 返回 0。前导空格同理返回 0。长度参数大于实际字符串长度时，null 终止符会正确截断——这一点很重要，因为 ustar 的 size 字段是 12 字节，但实际有效数字可能只有后面几位。</p><p><strong>验证</strong>: 编写测试验证典型输入：&quot;00000000012&quot; 解析为 10，&quot;00000001000&quot; 解析为 512。同时测试 null 终止 、空格终止、零长度、全零、大值（全 7 字符串等于约 8.6GB）等边界情况。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>本篇只涉及头文件定义，不需要单独运行内核。但你可以运行 host 端单元测试来验证格式定义和转换函数的正确性：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test_ramdisk</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ctest</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ramdisk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output-on-failure</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>预期输出：所有八进制转换测试通过（约 15 个测试用例），头部结构体大小和偏移量测试通过（约 8 个测试用例） 。你应该能看到类似 &quot;ramdisk_ustar_header: sizeof(UstarHeader) is 512 ... OK&quot; 和 &quot;ramdisk_octal: &#39;12&#39; returns 10 ... OK&quot; 的输出。</p><p>如果某个偏移量测试失败，测试会打印期望值和实际值，方便你定位是哪个字段定义有误。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p>如果你发现结构体大小不等于 512，首先检查是否漏掉了 packed 属性。如果某个字段的偏移量不对，检查字段 排列顺序是否与 POSIX 规范一致——顺序错了的话中间的字段全都会偏移。在调试时，可以创建一个全零的头部 实例，获取其基地址指针，然后分别计算每个字段成员的地址与基地址的差值，与预期偏移量做比较。</p><p>如果八进制转换函数对某些输入返回了错误值，打印输入字符串的每个字符和它的 ASCII 码值，确认不是隐藏的 非 ASCII 字符在捣鬼。特别要注意制表符和其他空白字符——它们不是空格也不是 null，函数会尝试把它们当作 八进制数字来解析，结果会出错。</p><p>如果你怀疑 tar 工具生成的归档格式有问题，可以用 hexdump 检查前几个头部的内容，确认各字段确实是 ASCII 八进制字符串。具体命令是 hexdump -C initrd.tar | head -40，你应该能在偏移 257 处看到 &quot;ustar&quot; 字样。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>要点</th></tr></thead><tbody><tr><td>ustar 格式</td><td>POSIX.1-1988，512 字节头部加数据块，末尾全零块标记结束</td></tr><tr><td>八进制 ASCII</td><td>数字字段存为八进制字符串，null 或空格终止，跨平台兼容</td></tr><tr><td>UstarHeader</td><td>packed struct 精确映射 512 字节布局，编译期断言兜底</td></tr><tr><td>octal_to_uint</td><td>逐字符解析，遇 null 或空格停止，位移累积</td></tr><tr><td>magic 字段</td><td>偏移 257，值为 &quot;ustar&quot;，验证头部合法性</td></tr><tr><td>typeflag</td><td>偏移 156，&#39;0&#39; 为文件，&#39;5&#39; 为目录，&#39;7&#39; 为连续文件</td></tr><tr><td>数据块对齐</td><td>文件数据按 512 字节向上取整，size 为 0 时无数据块</td></tr></tbody></table><p>下一篇我们将搭建构建系统管道——把这个 ustar 格式的归档&quot;塞进&quot;内核二进制镜像里。</p>`,63)])])}const k=a(i,[["render",o]]);export{c as __pageData,k as default};
